MapResolvablePriceQuantity.logic:
set resolvablePriceQuantity:
    ResolvablePriceQuantity {
        quantitySchedule: if fpmlReturnSwapNotional -> notionalAmount -> amount exists
                then MapNotionalAmountToQuantityWithAddress(
                        fpmlReturnSwapNotional -> notionalAmount -> amount,
                        fpmlLeg
                    )
            // this should not be necessary, the reporting logic should simply check the quantity reference
            else if fpmlReturnSwapNotional -> relativeNotionalAmount -> href exists
                    and fpmlReturnSwapNotional -> relativeNotionalAmount -> href = fpmlOtherReturnSwapNotional -> notionalAmount -> id
            then MapNotionalAmountToQuantityWithAddress(
                        fpmlOtherReturnSwapNotional -> notionalAmount -> amount,
                        fpmlOtherLeg
                    ),
        quantityReference: MapResolvablePriceQuantityReference(
                    fpmlReturnSwapNotional -> relativeNotionalAmount -> href
                ),
        reset: if fpmlReturnSwapNotional -> notionalAmount -> amount exists
                then fpmlReset,
        ...
    } with-meta {
        key: fpmlReturnSwapNotional -> notionalAmount -> id
    }

